    vector<long long> unique_weights;
    unique_weights.push_back(edges[0][2]);
    for (int i = 1; i < edges.size(); ++i) {
        if (edges[i][2] != edges[i-1][2]) {
            unique_weights.push_back(edges[i][2]);
        }
    }

    long long low = 0;
    long long high = unique_weights.back();
    long long answer = high;

    while (low <= high) {
        long long mid = (low + high) / 2;
        DSU dsu(n);
        for (auto& e : edges) {
            if (e[2] <= mid) {
                dsu.union(e[0], e[1]);
            }
        }
        int components = dsu.get_components();
        if (components <= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    return answer;
}
